svg.script:
function qslSearch(){
  var term=prompt('Search frame (regex):','');
  var detail=document.getElementById('qsl-detail');
  var gs=document.getElementsByClassName('func');
  var i;
  if(!term){for(i=0;i<gs.length;i++){gs[i].getElementsByTagName('rect')[0].classList.remove('hl');}if(detail)detail.textContent=' ';return;}
  var re;try{re=new RegExp(term);}catch(e){return;}
  for(i=0;i<gs.length;i++){var r=gs[i].getElementsByTagName('rect')[0];
    if(re.test(gs[i].getAttribute('data-name'))){r.classList.add('hl');}
    else{r.classList.remove('hl');}}
  if(detail)detail.textContent='Search: '+term;
}
